%pyspark
class Node:
    def __init__(self, state, cost, parentNode, action):
        self.state = state
        self.cost = cost
        self.action = action
        self.parentNode = parentNode

    def getActions(self):
        actions = []
        node = self
        while node:
            if node.action is not None:
                actions.append(node.action)
            node = node.parentNode
        return list(reversed(actions))

