import copy
import random
import matplotlib.pyplot as plt
from PIL import Image as PILImage

class EightPuzzle:
    def __init__(self, img, emptyPos):
        self.emptyPos = emptyPos
        self.tiles = []
        
        for i in range(3):
            for j in range(3):
                box = (j * 300, i * 300, (j + 1) * 300, (i + 1) * 300)
                self.tiles.append({
                    'img': img.crop(box) if i * 3 + j != self.emptyPos else None,
                    'id': i * 3 + j
                })
        self.goal = self.getState()

    def getState(self):
        return [x['id'] for x in self.tiles]

    def getPosActions(self):
        state = self.getState()
        actions = [0, 1, 2, 3]
        emptyPos = state.index(self.emptyPos)

        if 0 <= emptyPos <= 2:
            actions.remove(0)
        if emptyPos in [2, 5, 8]:
            actions.remove(1)
        if 6 <= emptyPos <= 8:
            actions.remove(2)
        if emptyPos in [0, 3, 6]:
            actions.remove(3)

        return actions
    
    def __swap(self, ind1, ind2):
        self.tiles[ind1], self.tiles[ind2] = self.tiles[ind2], self.tiles[ind1]

    def getEmptyPos(self):
        for i, tile in enumerate(self.tiles):
            if tile['id'] == self.emptyPos:
                return i

    def action(self, actions):
        for action in actions:
            if action not in self.getPosActions():
                continue

            emptyPos = self.getEmptyPos()

            if action == 0:
                self.__swap(emptyPos, emptyPos - 3)
            elif action == 1:
                self.__swap(emptyPos, emptyPos + 1)
            elif action == 2:
                self.__swap(emptyPos, emptyPos + 3)
            elif action == 3:
                self.__swap(emptyPos, emptyPos - 1)

    def shuffle(self, n):
        for _ in range(n):
            action = random.choice(self.getPosActions())
            self.action([action])

    def show(self):
        state = self.getState()
        for i in range(3):
            print(state[3 * i:3 * i + 3])

    def showImgs(self, figSize):
        fig = plt.figure(figsize=figSize)
        i = 1
        for tile in self.tiles:
            _ = fig.add_subplot(3, 3, i)
            if tile['img'] is not None:
                plt.imshow(tile['img'])
            i += 1
        plt.show()

    def getProblemAfterAction(self, actions):
        new_problem = copy.deepcopy(self)
        new_problem.action(actions)
        return new_problem

