class BfsSolver:
    def train(self, problem):
        self.problem = problem

    def solve(self):
        node = self.__search()
        return node.getActions() if node else None

    def __search(self):
        initNode = Node(self.problem.getState(), 0, None, None)
        frontiers = [initNode]
        reached = {tuple(initNode.state): initNode}

        while frontiers:
            node = frontiers.pop(0)
            if node.state == self.problem.goal:
                return node
            for childNode in self.__expand(node):
                state = childNode.state
                if tuple(state) not in reached or childNode.cost < reached[tuple(state)].cost:
                    reached[tuple(state)] = childNode
                    frontiers.append(childNode)

        return None

    def __expand(self, node):
        problem = self.problem.getProblemAfterAction(node.getActions())
        posActions = problem.getPosActions()

        for action in posActions:
            new_problem = problem.getProblemAfterAction([action])
            curState = new_problem.getState()
            yield Node(curState, node.cost + 1, node, action)
